import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote — base premiums for main items (new customer, single item)
  it("quotes a sword for a new customer (base 100 + 10% first + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quotes an amulet for a new customer", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it.todo("quotes a staff for a new customer");
  it.todo("quotes a potion for a new customer");

  // Quote — components
  it.todo("quotes a single rune component for a new customer");
  it.todo("quotes 3 alike runes as a building block (60 G base)");

  // Quote — risk surcharges
  it.todo("adds 50% cursed surcharge to a sword premium");
  it.todo("adds 30% high enchantment surcharge to a sword (enchantment ≥ 5)");

  // Quote — customer discounts and surcharges
  it.todo("applies 20% loyalty discount for long-standing customers (≥ 2 years)");
  it.todo("applies 15% subsequent-contract discount to the second quote in a scenario");

  // Claims — base behaviour
  it.todo("pays out a simple amulet claim minus 100 G deductible and reports remaining cap");
  it.todo("caps total payout at twice the insurance sum across multiple claims");
  it.todo("reimburses damage to enchantment ≥ 8 items at 50%");
  it.todo("fully reimburses damage to dragon-material items");
});

