export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type QuoteStep = {
  op: "quote";
  items: Item[];
};

export type Step = QuoteStep;

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type StepResult = QuoteResult;

export type ScenarioResult = {
  results: StepResult[];
};

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const FIRST_INSURANCE_SURCHARGE = 0.1;
const PROCESSING_FEE = 5;

const basePremiumOf = (item: Item): number => BASE_PREMIUMS[item.type];

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    const base = step.items.reduce((sum, item) => sum + basePremiumOf(item), 0);
    const withFirstSurcharge = base + base * FIRST_INSURANCE_SURCHARGE;
    const premium = withFirstSurcharge + PROCESSING_FEE;
    return { premium };
  });
  return { results };
};

