export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type QuoteStep = {
  op: "quote";
  items: Item[];
};

export type Step = QuoteStep;

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type StepResult = QuoteResult;

export type ScenarioResult = {
  results: StepResult[];
};

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune"]);
const BLOCK_OF_THREE_PREMIUM = 60;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const PROCESSING_FEE = 5;

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const basePremiumForGroup = (type: string, count: number): number => {
  if (COMPONENT_TYPES.has(type)) {
    const blocks = Math.floor(count / 3);
    const remainder = count - blocks * 3;
    return blocks * BLOCK_OF_THREE_PREMIUM + remainder * BASE_PREMIUMS[type];
  }
  return count * BASE_PREMIUMS[type];
};

const basePremium = (items: Item[]): number => {
  let total = 0;
  for (const [type, count] of countByType(items)) {
    total += basePremiumForGroup(type, count);
  }
  return total;
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    const base = basePremium(step.items);
    const withFirstSurcharge = base + base * FIRST_INSURANCE_SURCHARGE;
    const premium = Math.ceil(withFirstSurcharge) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
};

