  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type QuoteStep = {
  op: "quote";
  items: Item[];
};

export type Step = QuoteStep;

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type StepResult = QuoteResult;

export type ScenarioResult = {
  results: StepResult[];
};

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;
const CURSED_SURCHARGE = 0.5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const PROCESSING_FEE = 5;

const riskMultiplier = (item: Item): number => {
  let multiplier = 1;
  if (item.cursed) multiplier += CURSED_SURCHARGE;
  return multiplier;
};

const componentGroupBase = (count: number, perItem: number): number => {
  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
  const remainder = count - blocks * COMPONENT_BLOCK_SIZE;
  return blocks * COMPONENT_BLOCK_PREMIUM + remainder * perItem;
};

const groupByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const list = groups.get(item.type) ?? [];
    list.push(item);
    groups.set(item.type, list);
  }
  return groups;
};

const groupBase = (type: string, items: Item[]): number => {
  const perItem = BASE_PREMIUMS[type];
  if (COMPONENT_TYPES.has(type)) {
    const groupTotal = componentGroupBase(items.length, perItem);
    const itemBase = groupTotal / items.length;
    return items.reduce((sum, item) => sum + itemBase * riskMultiplier(item), 0);
  }
  return items.reduce((sum, item) => sum + perItem * riskMultiplier(item), 0);
};

const basePremium = (items: Item[]): number => {
  let total = 0;
  for (const [type, group] of groupByType(items)) {
    total += groupBase(type, group);
  }
  return total;
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    const base = basePremium(step.items);
    const withFirstSurcharge = base + base * FIRST_INSURANCE_SURCHARGE;
    const premium = Math.ceil(withFirstSurcharge) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
};

